=powershell -NoProfile -ExecutionPolicy Bypass -Command "$paths = @({{ (()=>{

  // --- базовый путь видео-папки ---
  const baseSettings = $('Base Settings').item.json;
  const root = `${baseSettings.channelsFolderPath}/${baseSettings.channelName}`;

  // --- дерево папок ---
  const tree = {
    "RUNPOD":  ["runpodRequests"],
    "VIDEOS":  [""],
  };

  // --- разворачиваем в полный список путей ---
  const paths = [root];

  for (const [main, subs] of Object.entries(tree)) {
    const mainPath = `${root}/${main}`;
    paths.push(mainPath);

    for (const sub of subs) {
      if (!sub) continue; // пропускаем пустые
      paths.push(`${mainPath}/${sub}`);
    }
  }

  // Если тебе нужны PowerShell-литералы строк (в одинарных кавычках):
  // return paths.map(p => `'${p.replace(/'/g, "''")}'`);

  // Если нужен просто массив путей (лучше для дальнейшей обработки):
  return paths.map(i=>"'"+i+"'");
})() }}); foreach($p in $paths){ New-Item -ItemType Directory -Path $p -Force | Out-Null}"

=powershell -NoProfile -ExecutionPolicy Bypass -Command "$paths = @({{ (()=>{
  // --- 5-символьный id из timestamp ($now) ---
  const alphabet = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ";
  let n = Math.floor(Date.parse($now)); // ms
  let randId = "";
  for (let i = 0; i < 5; i++) {
    randId = alphabet[n % 52] + randId;
    n = Math.floor(n / 52);
  }

  // --- базовый путь видео-папки ---
  const baseSettings = $('Base Settings').item.json;
  const root = `${baseSettings.channelsFolderPath}/${baseSettings.channelName}/VIDEOS/${$now.format('yyyy-MM-dd')}_${randId}`;

  // --- дерево папок ---
  const tree = {
    "TEXTS":  [""],
    "VOICE":  ["audioData", "transcript"],
    "IMAGES": ["imagePrompts", "images", "textParts"],
    "CLIPS":  ["startFrames", "videoClipsAndStartFramesPrompts", "videoClips"],
  };

  // --- разворачиваем в полный список путей ---
  const paths = [root];

  for (const [main, subs] of Object.entries(tree)) {
    const mainPath = `${root}/${main}`;
    paths.push(mainPath);

    for (const sub of subs) {
      if (!sub) continue; // пропускаем пустые
      paths.push(`${mainPath}/${sub}`);
    }
  }

  // Если тебе нужны PowerShell-литералы строк (в одинарных кавычках):
  // return paths.map(p => `'${p.replace(/'/g, "''")}'`);

  // Если нужен просто массив путей (лучше для дальнейшей обработки):
  return paths.map(i=>"'"+i+"'");
})() }}); foreach($p in $paths){ New-Item -ItemType Directory -Path $p -Force | Out-Null}"

